import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;

public class CSVFormatValidateTest {

    private CSVFormat csvFormat;
    private Method validateMethod;

    @BeforeEach
    public void setUp() throws Exception {
        // Use DEFAULT and then modify fields via reflection if needed
        csvFormat = CSVFormat.DEFAULT;

        // Access private validate method
        validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
    }

    private void invokeValidate(CSVFormat format) throws Exception {
        // invoke private method validate on given instance
        validateMethod.invoke(format);
    }

    @Test
    public void testValidateDelimiterIsLineBreak() throws Exception {
        CSVFormat format = csvFormat.withDelimiter('\n');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertEquals("The delimiter cannot be a line break", ex.getCause() == null ? ex.getMessage() : ex.getCause().getMessage());
    }

    @Test
    public void testValidateDelimiterEqualsQuoteCharacter() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(',').withQuote(',');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The quoteChar character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidateDelimiterEqualsEscapeCharacter() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(';').withEscape(';');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The escape character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidateDelimiterEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withDelimiter('#').withCommentMarker('#');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The comment start character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidateQuoteEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withQuote('!').withCommentMarker('!');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The comment start character and the quoteChar cannot be the same"));
    }

    @Test
    public void testValidateEscapeEqualsCommentMarker() throws Exception {
        CSVFormat format = csvFormat.withEscape('^').withCommentMarker('^');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The comment start and the escape character cannot be the same"));
    }

    @Test
    public void testValidateEscapeNullAndQuoteModeNone() throws Exception {
        CSVFormat format = csvFormat.withEscape((Character) null).withQuoteMode(QuoteMode.NONE);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertEquals("No quotes mode set but no escape character is set", ex.getMessage());
    }

    @Test
    public void testValidateHeaderDuplicateEntries() throws Exception {
        CSVFormat format = csvFormat.withHeader("a", "b", "a");
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assertTrue(ex.getMessage().contains("The header contains a duplicate entry: 'a'"));
        assertTrue(ex.getMessage().contains("[a, b, a]"));
    }

    @Test
    public void testValidateValidFormat() throws Exception {
        CSVFormat format = csvFormat.withDelimiter(',').withQuote('"').withEscape('\\').withCommentMarker('#')
                .withQuoteMode(QuoteMode.MINIMAL).withHeader("col1", "col2");
        // Should not throw
        assertDoesNotThrow(() -> invokeValidate(format));
    }
}
